// Some portions generated by Claude
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import java.util.List;

import org.eclipse.rdf4j.query.algebra.TupleExpr;

/**
 * One differential-test input: an original tree, a candidate derived from it, and how the pair was made (source, seed,
 * mutator chain) so every failure is reproducible. The expectation is advisory metadata for triage — the oracle never
 * uses it as ground truth, because evaluation is the only authority.
 */
record TreePair(
		String label,
		String sourceId,
		long seed,
		List<String> mutatorChain,
		TupleExpr original,
		TupleExpr candidate,
		Expectation expectation) {

	enum Expectation {
		PRESERVING,
		BREAKING,
		UNSPECIFIED
	}

	String describe() {
		return label + " [source=" + sourceId + ", seed=" + seed + ", mutators=" + mutatorChain + "]";
	}
}
